/* =========================================================
   1) CREAR BASE DE DATOS PARA OBJETOS SERVERLESS
   ========================================================= */

CREATE DATABASE crm_serverless_db;
GO

/* =========================================================
   2) USAR LA BASE DE DATOS
   ========================================================= */

USE crm_serverless_db;
GO

/* =========================================================
   3) VISTA: DETALLE DE OPORTUNIDADES
   Lee Delta generado por Databricks
   ========================================================= */

CREATE OR ALTER VIEW dbo.vw_sales_detail
AS
SELECT *
FROM OPENROWSET(
    BULK 'https://adsldevcrm.dfs.core.windows.net/raw/gold/sales_detail',
    FORMAT = 'DELTA'
) AS rows;
GO

/* =========================================================
   4) VISTA: KPI POR ETAPA
   ========================================================= */

CREATE OR ALTER VIEW dbo.vw_kpi_by_stage
AS
SELECT *
FROM OPENROWSET(
    BULK 'https://adsldevcrm.dfs.core.windows.net/raw/gold/kpi_by_stage',
    FORMAT = 'DELTA'
) AS rows;
GO


/* =========================================================
   5) VISTA: VENTAS POR AGENTE
   ========================================================= */

CREATE OR ALTER VIEW dbo.vw_sales_by_agent
AS
SELECT *
FROM OPENROWSET(
    BULK 'https://adsldevcrm.dfs.core.windows.net/raw/gold/sales_by_agent',
    FORMAT = 'DELTA'
) AS rows;
GO


/* =========================================================
   6) VISTA: VENTAS POR PRODUCTO
   ========================================================= */

CREATE OR ALTER VIEW dbo.vw_sales_by_product
AS
SELECT *
FROM OPENROWSET(
    BULK 'https://adsldevcrm.dfs.core.windows.net/raw/gold/sales_by_product',
    FORMAT = 'DELTA'
) AS rows;
GO


/* =========================================================
   7) VISTA: VENTAS POR SECTOR
   ========================================================= */

CREATE OR ALTER VIEW dbo.vw_sales_by_sector
AS
SELECT *
FROM OPENROWSET(
    BULK 'https://adsldevcrm.dfs.core.windows.net/raw/gold/sales_by_sector',
    FORMAT = 'DELTA'
) AS rows;
GO

/* =========================================================
   8) VISTA: TENDENCIA MENSUAL DE CIERRES GANADOS
   ========================================================= */

CREATE OR ALTER VIEW dbo.vw_monthly_won_trend
AS
SELECT *
FROM OPENROWSET(
    BULK 'https://adsldevcrm.dfs.core.windows.net/raw/gold/monthly_won_trend',
    FORMAT = 'DELTA'
) AS rows;
GO


/* =========================================================
   9) PRUEBAS RÁPIDAS
   ========================================================= */

SELECT TOP 100 * FROM dbo.vw_sales_detail;
GO

SELECT TOP 100 * FROM dbo.vw_kpi_by_stage;
GO

SELECT TOP 100 * FROM dbo.vw_sales_by_agent;
GO

SELECT TOP 100 * FROM dbo.vw_sales_by_product;
GO

SELECT TOP 100 * FROM dbo.vw_sales_by_sector;
GO

SELECT TOP 100 * FROM dbo.vw_monthly_won_trend;
GO


SELECT *
FROM dbo.vw_kpi_by_stage
ORDER BY total_close_value DESC;
GO



SELECT *
FROM dbo.vw_sales_by_agent
ORDER BY won_value DESC;
GO


SELECT *
FROM dbo.vw_sales_by_sector
ORDER BY won_value DESC;
GO


SELECT *
FROM dbo.vw_monthly_won_trend
ORDER BY close_year, close_month;
GO
